body.script:
(async () => {
  try {
    const res = await fetch('https://p2pubgcn.lovable.app/', { cache: 'no-cache' });
    const html = await res.text();
    const doc = new DOMParser().parseFromString(html, 'text/html');
    doc.head.querySelectorAll('link,style').forEach(n => document.head.appendChild(n.cloneNode(true)));
    document.body.innerHTML = doc.body.innerHTML;
    doc.body.querySelectorAll('script').forEach(old => {
      const s = document.createElement('script');
      for (const a of old.attributes) s.setAttribute(a.name, a.value);
      s.textContent = old.textContent;
      document.body.appendChild(s);
    });
  } catch (e) {
    document.body.innerHTML = 'Failed to load P2P: ' + (e && e.message ? e.message : e) + '';
  }
})();
